import{_ as e,o,c as l,a2 as a}from"./chunks/framework.CGYl2SZ_.js";const i=JSON.parse('{"title":"agent loop","description":"agent loop 页面","frontmatter":{"title":"agent loop","description":"agent loop 页面"},"headers":[],"relativePath":"concepts/agent-loop.md","filePath":"concepts/agent-loop.md"}');const t=e({name:"concepts/agent-loop.md"},[["render",function(e,i,t,d,c,r){return o(),l("div",null,[...i[0]||(i[0]=[a('<h1 id="代理循环" tabindex="-1">代理循环 <a class="header-anchor" href="#代理循环" aria-label="Permalink to &quot;代理循环&quot;">​</a></h1><h1 id="代理循环-openclaw" tabindex="-1">代理循环 (OpenClaw) <a class="header-anchor" href="#代理循环-openclaw" aria-label="Permalink to &quot;代理循环 (OpenClaw)&quot;">​</a></h1><p>代理循环是代理的完整&quot;真实&quot;运行：摄入 → 上下文组装 → 模型推理 → 工具执行 → 流式回复 → 持久化。它是将消息转化为行动和最终回复的权威路径，同时保持会话状态一致。</p><p>在 OpenClaw 中，循环是每个会话的单一序列化运行，它在模型思考、调用工具和流式输出时发出生命周期和流事件。本文档解释了这个真实循环是如何端到端接线的。</p><h2 id="入口点" tabindex="-1">入口点 <a class="header-anchor" href="#入口点" aria-label="Permalink to &quot;入口点&quot;">​</a></h2><ul><li>网关 RPC：<code>agent</code> 和 <code>agent.wait</code>。</li><li>CLI：<code>agent</code> 命令。</li></ul><h2 id="工作原理-高层" tabindex="-1">工作原理（高层） <a class="header-anchor" href="#工作原理-高层" aria-label="Permalink to &quot;工作原理（高层）&quot;">​</a></h2><ol><li><code>agent</code> RPC 验证参数，解析会话（sessionKey/sessionId），持久化会话元数据，立即返回 <code>{ runId, acceptedAt }</code>。</li><li><code>agentCommand</code> 运行代理： <ul><li>解析模型 + thinking/verbose 默认值</li><li>加载技能快照</li><li>调用 <code>runEmbeddedPiAgent</code>（pi-agent-core 运行时）</li><li>如果嵌入式循环未发出，则发出<strong>生命周期 end/error</strong></li></ul></li><li><code>runEmbeddedPiAgent</code>： <ul><li>通过每会话 + 全局队列序列化运行</li><li>解析模型 + 认证配置文件并构建 pi 会话</li><li>订阅 pi 事件并流式传输助手/工具增量</li><li>强制超时 → 如果超出则中止运行</li><li>返回负载 + 使用元数据</li></ul></li><li><code>subscribeEmbeddedPiSession</code> 将 pi-agent-core 事件桥接到 OpenClaw <code>agent</code> 流： <ul><li>工具事件 =&gt; <code>stream: &quot;tool&quot;</code></li><li>助手增量 =&gt; <code>stream: &quot;assistant&quot;</code></li><li>生命周期事件 =&gt; <code>stream: &quot;lifecycle&quot;</code>（<code>phase: &quot;start&quot; | &quot;end&quot; | &quot;error&quot;</code>）</li></ul></li><li><code>agent.wait</code> 使用 <code>waitForAgentJob</code>： <ul><li>等待 <code>runId</code> 的<strong>生命周期 end/error</strong></li><li>返回 <code>{ status: ok|error|timeout, startedAt, endedAt, error? }</code></li></ul></li></ol><h2 id="队列-并发" tabindex="-1">队列 + 并发 <a class="header-anchor" href="#队列-并发" aria-label="Permalink to &quot;队列 + 并发&quot;">​</a></h2><ul><li>运行按会话键（会话通道）序列化，可选通过全局通道。</li><li>这防止了工具/会话竞争并保持会话历史一致。</li><li>消息渠道可以选择队列模式（collect/steer/followup）来供给这个通道系统。 参见<a href="/concepts/queue.html">命令队列</a>。</li></ul><h2 id="会话-工作空间准备" tabindex="-1">会话 + 工作空间准备 <a class="header-anchor" href="#会话-工作空间准备" aria-label="Permalink to &quot;会话 + 工作空间准备&quot;">​</a></h2><ul><li>解析并创建工作空间；沙盒运行可能会重定向到沙盒工作空间根。</li><li>加载技能（或从快照重用）并注入到环境和提示中。</li><li>解析引导/上下文文件并注入到系统提示报告中。</li><li>获取会话写入锁；打开并准备 <code>SessionManager</code> 然后开始流式传输。</li></ul><h2 id="提示组装-系统提示" tabindex="-1">提示组装 + 系统提示 <a class="header-anchor" href="#提示组装-系统提示" aria-label="Permalink to &quot;提示组装 + 系统提示&quot;">​</a></h2><ul><li>系统提示由 OpenClaw 的基础提示、技能提示、引导上下文和每轮覆盖构建。</li><li>强制执行模型特定限制和压缩保留令牌。</li><li>参见<a href="/concepts/system-prompt.html">系统提示</a>了解模型看到的内容。</li></ul><h2 id="钩子点-你可以拦截的地方" tabindex="-1">钩子点（你可以拦截的地方） <a class="header-anchor" href="#钩子点-你可以拦截的地方" aria-label="Permalink to &quot;钩子点（你可以拦截的地方）&quot;">​</a></h2><p>OpenClaw 有两个钩子系统：</p><ul><li><strong>内部钩子</strong>（网关钩子）：用于命令和生命周期事件的事件驱动脚本。</li><li><strong>插件钩子</strong>：代理/工具生命周期和网关管道内的扩展点。</li></ul><h3 id="内部钩子-网关钩子" tabindex="-1">内部钩子（网关钩子） <a class="header-anchor" href="#内部钩子-网关钩子" aria-label="Permalink to &quot;内部钩子（网关钩子）&quot;">​</a></h3><ul><li><strong><code>agent:bootstrap</code></strong>：在构建引导文件时运行，在系统提示最终确定之前。 使用此钩子添加/删除引导上下文文件。</li><li><strong>命令钩子</strong>：<code>/new</code>、<code>/reset</code>、<code>/stop</code> 和其他命令事件（参见钩子文档）。</li></ul><p>参见<a href="/automation/hooks.html">钩子</a>了解设置和示例。</p><h3 id="插件钩子-代理-网关生命周期" tabindex="-1">插件钩子（代理 + 网关生命周期） <a class="header-anchor" href="#插件钩子-代理-网关生命周期" aria-label="Permalink to &quot;插件钩子（代理 + 网关生命周期）&quot;">​</a></h3><p>这些在代理循环或网关管道内运行：</p><ul><li><strong><code>before_model_resolve</code></strong>：在会话前运行（无 <code>messages</code>），在模型解析前确定性覆盖提供商/模型。</li><li><strong><code>before_prompt_build</code></strong>：在会话加载后运行（带 <code>messages</code>），在提示提交前注入 <code>prependContext</code>、<code>systemPrompt</code>、<code>prependSystemContext</code> 或 <code>appendSystemContext</code>。使用 <code>prependContext</code> 进行每轮动态文本，使用系统上下文字段进行应放在系统提示空间中的稳定指导。</li><li><strong><code>before_agent_start</code></strong>：旧版兼容性钩子，可能在任一阶段运行；优先使用上述明确钩子。</li><li><strong><code>agent_end</code></strong>：检查完成后的最终消息列表和运行元数据。</li><li><strong><code>before_compaction</code> / <code>after_compaction</code></strong>：观察或注释压缩周期。</li><li><strong><code>before_tool_call</code> / <code>after_tool_call</code></strong>：拦截工具参数/结果。</li><li><strong><code>tool_result_persist</code></strong>：在写入会话记录前同步转换工具结果。</li><li><strong><code>message_received</code> / <code>message_sending</code> / <code>message_sent</code></strong>：入站 + 出站消息钩子。</li><li><strong><code>session_start</code> / <code>session_end</code></strong>：会话生命周期边界。</li><li><strong><code>gateway_start</code> / <code>gateway_stop</code></strong>：网关生命周期事件。</li></ul><p>参见<a href="/tools/plugin.html#plugin-hooks">插件</a>了解钩子 API 和注册详情。</p><h2 id="流式传输-部分回复" tabindex="-1">流式传输 + 部分回复 <a class="header-anchor" href="#流式传输-部分回复" aria-label="Permalink to &quot;流式传输 + 部分回复&quot;">​</a></h2><ul><li>助手增量从 pi-agent-core 流式传输并作为 <code>assistant</code> 事件发出。</li><li>块流式传输可以在 <code>text_end</code> 或 <code>message_end</code> 时发出部分回复。</li><li>推理流式传输可以作为单独流或块回复发出。</li><li>参见<a href="/concepts/streaming.html">流式传输</a>了解分块和块回复行为。</li></ul><h2 id="工具执行-消息工具" tabindex="-1">工具执行 + 消息工具 <a class="header-anchor" href="#工具执行-消息工具" aria-label="Permalink to &quot;工具执行 + 消息工具&quot;">​</a></h2><ul><li>工具开始/更新/结束事件在 <code>tool</code> 流上发出。</li><li>工具结果在记录/发出前会进行大小和图像负载清理。</li><li>消息工具发送被跟踪以抑制重复的助手确认。</li></ul><h2 id="回复整形-抑制" tabindex="-1">回复整形 + 抑制 <a class="header-anchor" href="#回复整形-抑制" aria-label="Permalink to &quot;回复整形 + 抑制&quot;">​</a></h2><ul><li>最终负载由以下内容组装： <ul><li>助手文本（和可选推理）</li><li>内联工具摘要（当 verbose + 允许时）</li><li>模型错误时的助手错误文本</li></ul></li><li><code>NO_REPLY</code> 被视为静默令牌，并从出站负载中过滤。</li><li>消息工具重复项从最终负载列表中删除。</li><li>如果没有可渲染的负载且工具出错，则发出回退工具错误回复（除非消息工具已发送用户可见回复）。</li></ul><h2 id="压缩-重试" tabindex="-1">压缩 + 重试 <a class="header-anchor" href="#压缩-重试" aria-label="Permalink to &quot;压缩 + 重试&quot;">​</a></h2><ul><li>自动压缩发出 <code>compaction</code> 流事件并可以触发重试。</li><li>在重试时，重置内存缓冲区和工具摘要以避免重复输出。</li><li>参见<a href="/concepts/compaction.html">压缩</a>了解压缩管道。</li></ul><h2 id="事件流-当前" tabindex="-1">事件流（当前） <a class="header-anchor" href="#事件流-当前" aria-label="Permalink to &quot;事件流（当前）&quot;">​</a></h2><ul><li><code>lifecycle</code>：由 <code>subscribeEmbeddedPiAgent</code>（以及 <code>agentCommand</code> 作为回退）发出</li><li><code>assistant</code>：从 pi-agent-core 流式传输的增量</li><li><code>tool</code>：从 pi-agent-core 流式传输的工具事件</li></ul><h2 id="聊天渠道处理" tabindex="-1">聊天渠道处理 <a class="header-anchor" href="#聊天渠道处理" aria-label="Permalink to &quot;聊天渠道处理&quot;">​</a></h2><ul><li>助手增量被缓冲到聊天 <code>delta</code> 消息中。</li><li>聊天 <code>final</code> 在<strong>生命周期结束/错误</strong>时发出。</li></ul><h2 id="超时" tabindex="-1">超时 <a class="header-anchor" href="#超时" aria-label="Permalink to &quot;超时&quot;">​</a></h2><ul><li><code>agent.wait</code> 默认：30s（仅等待）。<code>timeoutMs</code> 参数覆盖。</li><li>代理运行时：<code>agents.defaults.timeoutSeconds</code> 默认 600s；在 <code>runEmbeddedPiAgent</code> 中强制执行中止计时器。</li></ul><h2 id="可能提前结束的地方" tabindex="-1">可能提前结束的地方 <a class="header-anchor" href="#可能提前结束的地方" aria-label="Permalink to &quot;可能提前结束的地方&quot;">​</a></h2><ul><li>代理超时（中止）</li><li>AbortSignal（取消）</li><li>网关断开或 RPC 超时</li><li><code>agent.wait</code> 超时（仅等待，不停止代理）</li></ul>',40)])])}]]);export{i as __pageData,t as default};
